import{bV as s,aL as e,u as i,G as t}from"./chunks/framework.D_inzUUb.js";const k=JSON.parse('{"title":"Tunnelbroker IPv6 教程","description":"","frontmatter":{"title":"Tunnelbroker IPv6 教程","date":"2020-09-30T00:00:00.000Z","categories":["网络运维"],"tags":["ipv6","tunnelbroker","阿里云","he"]},"headers":[],"relativePath":"posts/202009/30-tunnelbroker-ipv6.md","filePath":"posts/202009/30-tunnelbroker-ipv6.md","lastUpdated":1777371762000}'),n={name:"posts/202009/30-tunnelbroker-ipv6.md"};function l(p,a,h,r,o,d){return e(),i("div",null,[...a[0]||(a[0]=[t(`<h1 id="tunnelbroker-ipv6-教程" tabindex="-1">Tunnelbroker IPv6 教程 <a class="header-anchor" href="#tunnelbroker-ipv6-教程" aria-label="Permalink to &quot;Tunnelbroker IPv6 教程&quot;">​</a></h1><p>通过 <a href="https://www.tunnelbroker.net/" target="_blank" rel="noreferrer">Tunnelbroker</a> 为不支持 IPv6 的服务器（如阿里云）配置 IPv6 隧道。</p><h2 id="一、启用-ipv6" tabindex="-1">一、启用 IPv6 <a class="header-anchor" href="#一、启用-ipv6" aria-label="Permalink to &quot;一、启用 IPv6&quot;">​</a></h2><p>阿里云等云服务器默认禁用 IPv6，需要手动开启：</p><p>编辑 <code>/etc/sysctl.conf</code>，将以下三项修改为 <code>0</code>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">net.ipv6.conf.all.disable_ipv6</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">net.ipv6.conf.default.disable_ipv6</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">net.ipv6.conf.lo.disable_ipv6</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span></span></code></pre></div><h2 id="二、添加-ipv6-dns" tabindex="-1">二、添加 IPv6 DNS <a class="header-anchor" href="#二、添加-ipv6-dns" aria-label="Permalink to &quot;二、添加 IPv6 DNS&quot;">​</a></h2><p>编辑 <code>/etc/resolvconf/resolv.conf.d/base</code>，添加：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>nameserver 2001:4860:4860::8844</span></span>
<span class="line"><span>nameserver 2001:470:20::2</span></span></code></pre></div><p>保存后执行：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">resolvconf</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span></span></code></pre></div><h2 id="三、配置网络接口" tabindex="-1">三、配置网络接口 <a class="header-anchor" href="#三、配置网络接口" aria-label="Permalink to &quot;三、配置网络接口&quot;">​</a></h2><p>编辑网络接口文件：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vi</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/network/interfaces</span></span></code></pre></div><p>在 Tunnelbroker 获取隧道信息后，添加 <code>he-ipv6</code> 接口配置。</p><h2 id="四、启动隧道" tabindex="-1">四、启动隧道 <a class="header-anchor" href="#四、启动隧道" aria-label="Permalink to &quot;四、启动隧道&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ifup</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> he-ipv6</span></span></code></pre></div><h2 id="五、重启网络模块" tabindex="-1">五、重启网络模块 <a class="header-anchor" href="#五、重启网络模块" aria-label="Permalink to &quot;五、重启网络模块&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/etc/init.d/network</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restart</span></span></code></pre></div><h2 id="六、验证" tabindex="-1">六、验证 <a class="header-anchor" href="#六、验证" aria-label="Permalink to &quot;六、验证&quot;">​</a></h2><p>执行 <code>ifconfig</code>，应能看到 <code>he-ipv6</code> 网卡。</p><p>测试 IPv6 连通性：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ping6</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 5</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 2001:4860:4860::8888</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ping6</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 5</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ipv6.google.com</span></span></code></pre></div><p>Ping 通表示网络已连通，能正常解析域名说明 DNS 也正常。</p><h2 id="ipv6-测试工具" tabindex="-1">IPv6 测试工具 <a class="header-anchor" href="#ipv6-测试工具" aria-label="Permalink to &quot;IPv6 测试工具&quot;">​</a></h2><ul><li><a href="https://ipv6-test.com/" target="_blank" rel="noreferrer">https://ipv6-test.com/</a></li><li><a href="https://ipv6test.google.com/" target="_blank" rel="noreferrer">https://ipv6test.google.com/</a></li><li><a href="http://test-ipv6.com/" target="_blank" rel="noreferrer">http://test-ipv6.com/</a></li></ul>`,26)])])}const b=s(n,[["render",l]]);export{k as __pageData,b as default};
